urse_id": "528", "course_tagline": "Navigate the Intersection of AI and Ethics in Business Landscape", "certificate_code": "AC-120", "feature_image_url": "https://www.aicerts.ai/wp-content/uploads/2024/02/AIC_AI-Ethics.svg", "certificate_overview": {"exam_format": "50 questions, 70% passing, 90 minutes, online proctored exam ", "prerequisites": "Basic knowledge of artificial intelligence, machine learning concepts, Python familiarity, fundamental AI/ML concepts ", "included_items": "Instructor-led OR Self-paced course + Official exam + Digital badge", "certificate_duration": "<ul>\\n<li><span data-contrast=\\"auto\\"> Instructor-Led: 1 day (live or virtual) </span></li>\\n<li><span data-contrast=\\"auto\\"> Self-Paced: 8 hours of content</span></li>\\n</ul>\\n"}, "certification_modules": [{"certification_module_title": "Course Overview", "certification_module_description": "<ol>\\n<li>Course Introduction <a href=\\"https://www.youtube.com/watch?v=HZk2x7nP5DQ\\">Preview</a></li>\\n</ol>\\n"}, {"certification_module_title": "Module 1: Overview of AI Ethics & Societal Impact", "certification_module_description": "<ol>\\n<li>1.1 Introduction to Ethical Considerations in AI <a href=\\"https://www.youtube.com/watch?v=byAACOT6ACM\\">Preview</a></li>\\n<li>1.2 Understanding The Societal Impact of AI Technologies <a href=\\"https://www.youtube.com/watch?v=y0HsN0DrPpQ\\">Preview</a></li>\\n<li>1.3 Strategies for Conducting Social and Ethical Impact Assessments</li>\\n</ol>\\n"}, {"certification_module_title": "Module 2: Bias and Fairness in AI", "certification_module_description": "<ol>\\n<li>2.1 Exploration of Biases in Data and Algorithms <a href=\\"https://www.youtube.com/watch?v=sBt-VbrFBQI\\">Preview</a></li>\\n<li>2.2 Strategies for Mitigating Bias and Ensuring Fairness in AI Systems</li>\\n</ol>\\n"}, {"certification_module_title": "Module 3: Transparency and Explainable AI", "certification_module_description": "<ol>\\n<li>3.1 Importance of Transparent AI Systems <a href=\\"https://www.youtube.com/watch?v=JTOkyhDhvqk\\">Preview</a></li>\\n<li>3.2 Techniques for Explaining AI Models to Diverse Stakeholders <a href=\\"https://www.youtube.com/watch?v=bI2gLX9Ab2A\\">Preview</a></li>\\n<li>3.3 Guided Projects on Designing and Analysis of AI Systems with Ethical Considerations</li>\\n</ol>\\n"}, {"certification_module_title": "Module 4: Privacy and Security Issues in AI", "certification_module_description": "<ol>\\n<li>Study frameworks for holding organizations accountable for the ethical use of AI.</li>\\n<li>Why it matters: Ensures ethical AI deployment and helps mitigate the consequences of potential misuse or harm.</li>\\n</ol>\\n"}, {"certification_module_title": " Module 5: Accountability and Responsibility", "certification_module_description": "<ol>\\n<li>5.1 Concepts of Accountability in AI Development and Deployment</li>\\n<li>5.2 Responsibilities of AI Practitioners and Organizations</li>\\n</ol>\\n"}, {"certification_module_title": " Module 6: Legal and Regulatory Issues", "certification_module_description": "<ol>\\n<li>6.1 Overview of Relevant Laws and Regulations Pertaining to AI</li>\\n<li>6.2 Understanding the Global Regulatory Issues for AI Technologies</li>\\n<li>6.3 Case Studies: GDPR Compliance</li>\\n<li>6.4 Legal Compliance of AI Tools</li>\\n</ol>\\n"}, {"certification_module_title": "Module 7: Ethical Decision-Making Frameworks", "certification_module_description": "<ol>\\n<li>7.1 Introduction to Frameworks for Making Ethical Decisions in AI</li>\\n<li>7.2 Case Studies and Applications of Ethical Decision-Making</li>\\n<li>7.3 Use of Simulation Platforms in Ethical Decision-Making</li>\\n</ol>\\n"}, {"certification_module_title": "Module 8: AI Governance & Best Practices", "certification_module_description": "<ol>\\n<li>8.1 Principles and Functions of International AI Governance</li>\\n<li>8.2 Best Practices for Integrating AI Ethics into Organizational Policies</li>\\n<li>8.3 Case Studies on AI Governance</li>\\n</ol>\\n"}, {"certification_module_title": "Module 9: Global AI Ethics Standards", "certification_module_description": "<ol>\\n<li>9.1 Explore Standards: IEEE&#8217;s Ethically Aligned Design</li>\\n<li>9.2 Comparative Case Studies on Standard Implementations</li>\\n<li>9.3 Tools for Evaluating AI Systems Against Global Standards</li>\\n</ol>\\n"}, {"certification_module_title": "Optional Module: AI Agents for Ethics and Its Implications", "certification_module_description": "<ol>\\n<li>1. Understanding AI Agents</li>\\n<li>2. Case Studies</li>\\n<li>3. Hands-On Practice with AI Agents</li>\\n</ol>\\n"}], "feature_image_jpg_url": "https://wsrv.nl/?url=https%3A%2F%2Fwww.aicerts.ai%2Fwp-content%2Fuploads%2F2024%2F02%2FAIC_AI-Ethics.svg&output=jpg", "who_should_enroll_points": [{"who_should_enroll_point": "<p><strong><span class=\\"TextRun SCXW199522337 BCX8\\" lang=\\"EN-US\\" xml:lang=\\"EN-US\\" data-contrast=\\"auto\\"><span class=\\"NormalTextRun SCXW199522337 BCX8\\">Ethics Professionals</span></span></strong><span class=\\"TextRun SCXW199522337 BCX8\\" lang=\\"EN-US\\" xml:lang=\\"EN-US\\" data-contrast=\\"auto\\"><span class=\\"NormalTextRun SCXW199522337 BCX8\\"><strong>:</strong>Enhance your </span><span class=\\"NormalTextRun SCXW199522337 BCX8\\">expertise</span><span class=\\"NormalTextRun SCXW199522337 BCX8\\"> in AI ethics to guide responsible AI deployment.</span></span><span class=\\"EOP SCXW199522337 BCX8\\" data-ccp-props=\\"{&quot;201341983&quot;:0,&quot;335551550&quot;:1,&quot;335551620&quot;:1,&quot;335559738&quot;:0,&quot;335559739&quot;:160,&quot;335559740&quot;:278}\\"> </span></p>\\n"}, {"who_should_enroll_point": "<p><strong><span class=\\"TextRun SCXW267088818 BCX8\\" lang=\\"EN-US\\" xml:lang=\\"EN-US\\" data-contrast=\\"auto\\"><span class=\\"NormalTextRun SCXW267088818 BCX8\\">AI &amp; Data Enthusiasts</span></span></strong><span class=\\"TextRun SCXW267088818 BCX8\\" lang=\\"EN-US\\" xml:lang=\\"EN-US\\" data-contrast=\\"auto\\"><span c